        `INSERT INTO lab_test_catalog (test_code, test_name, base_price, category, is_active)
         VALUES ($1, $2, $3, 'Lab', true)
         ON CONFLICT (test_code) DO UPDATE
           SET test_name = EXCLUDED.test_name, base_price = EXCLUDED.base_price,
               is_active = true, updated_at = CURRENT_TIMESTAMP`,
        [a.code, a.name, a.price]
